-        }
-    } else if (QuantMode::STATIC_QUANT == quantMode) {
-        if (scaleShape->GetDimNum() == DIM_ONE) {
-            OP_CHECK(
-                scaleShape->GetDim(0) != NEG_ONE && scaleShape->GetDim(0) != NEG_TWO &&
-                    !isSameDim(scaleShape->GetDim(0), DIM_ONE),
-                OPS_LOG_E(
-                    context->GetNodeName(),
